// 鲁迅名言库
const quotes = [
"横眉冷对千夫指，俯首甘为孺子牛。",
"世上本没有路，走的人多了，也便成了路。",
"时间就像海绵里的水，只要愿挤，总还是有的。",
"不在沉默中爆发，就在沉默中灭亡。",
"其实地上本没有路，走的人多了，也便成了路。",
"哀其不幸，怒其不争。",
"真的猛士，敢于直面惨淡的人生，敢于正视淋漓的鲜血。",
"希望是本无所谓有，无所谓无的。这正如地上的路；其实地上本没有路，走的人多了，也便成了路。",
"人生最苦痛的是梦醒了无路可以走。",
"悲剧将人生的有价值的东西毁灭给人看，喜剧将那无价值的撕破给人看。"
];
// 获取DOM元素
const randomQuoteElement = document.getElementById('randomQuote');
const changeThemeBtn = document.getElementById('changeThemeBtn');
const showRandomQuoteBtn = document.getElementById('showRandomQuoteBtn');
const highlightBtn = document.getElementById('highlightBtn');
const messageElement = document.getElementById('message');
const visitCountElement = document.getElementById('count');
// 主题颜色数组
const themes = [
{ primary: '#8B0000', secondary: '#f9f3f3' }, // 默认主题
{ primary: '#2E8B57', secondary: '#f0f8f0' }, // 绿色主题
{ primary: '#4B0082', secondary: '#f5f0fa' }, // 紫色主题
{ primary: '#8B4513', secondary: '#f9f3e9' }  // 棕色主题
];
let currentThemeIndex = 0;
// 显示随机名言
function showRandomQuote() {
const randomIndex = Math.floor(Math.random() * quotes.length);
randomQuoteElement.textContent = `"${quotes[randomIndex]}"`;
// 显示消息
showMessage(`已显示随机名言：${quotes[randomIndex].substring(0, 20)}...`);
}
// 切换主题
function changeTheme() {
currentThemeIndex = (currentThemeIndex + 1) % themes.length;
const theme = themes[currentThemeIndex];
// 更新CSS变量
document.documentElement.style.setProperty('--primary-color', theme.primary);
// 更新页面元素颜色
const primaryElements = document.querySelectorAll('h1, h2, .subtitle, button');
primaryElements.forEach(el => {
if (el.tagName === 'BUTTON') {
el.style.backgroundColor = theme.primary;
} else {
el.style.color = theme.primary;
}
});
// 更新边框和引用框
document.querySelector('header').style.borderBottomColor = theme.primary;
const quotesElements = document.querySelectorAll('.quote');
quotesElements.forEach(quote => {
quote.style.borderLeftColor = theme.primary;
quote.style.backgroundColor = theme.secondary;
});
// 更新时间线圆点
const timelineItems = document.querySelectorAll('.timeline li:before');
showMessage(`已切换到主题 ${currentThemeIndex + 1}`);
}
// 高亮重要年份
function highlightImportantYears() {
const importantYears = ['1881', '1898', '1902', '1918', '1921', '1936'];
const timelineItems = document.querySelectorAll('.timeline li');
// 先移除所有高亮
timelineItems.forEach(item => {
item.innerHTML = item.innerHTML.replace(/<span class="highlight">(.*?)<\/span>/g, '$1');
});
// 高亮重要年份
timelineItems.forEach(item => {
importantYears.forEach(year => {
if (item.innerHTML.includes(year)) {
item.innerHTML = item.innerHTML.replace(
new RegExp(`(${year})`, 'g'),
'<span class="highlight">$1</span>'
);
}
});
});
showMessage(`已高亮 ${importantYears.length} 个重要年份`);
}
// 显示消息
function showMessage(text) {
messageElement.textContent = text;
messageElement.style.display = 'block';
// 3秒后隐藏消息
setTimeout(() => {
messageElement.style.display = 'none';
}, 3000);
}
// 更新访问次数
function updateVisitCount() {
let count = localStorage.getItem('luxunVisitCount');
if (!count) {
count = 1;
} else {
count = parseInt(count) + 1;
}
localStorage.setItem('luxunVisitCount', count);
visitCountElement.textContent = count;
}
// 初始化页面
function initPage() {
// 显示第一条随机名言
showRandomQuote();
// 更新访问次数
updateVisitCount();
// 添加事件监听器
changeThemeBtn.addEventListener('click', changeTheme);
showRandomQuoteBtn.addEventListener('click', showRandomQuote);
highlightBtn.addEventListener('click', highlightImportantYears);
// 添加键盘快捷键
document.addEventListener('keydown', (e) => {
if (e.key === 'q' || e.key === 'Q') {
showRandomQuote();
} else if (e.key === 't' || e.key === 'T') {
changeTheme();
} else if (e.key === 'h' || e.key === 'H') {
highlightImportantYears();
}
});
// 显示键盘快捷键提示
setTimeout(() => {
showMessage('提示：按 Q 随机名言，T 切换主题，H 高亮年份');
}, 2000);
}
// 页面加载完成后初始化
document.addEventListener('DOMContentLoaded', initPage);
</script>
</body>
</html>
```
